class ImageProcessingController < ApplicationController
  skip_before_action :verify_authenticity_token

  def convert_image
    uploaded_file = params[:image]
    format = params[:format]
    width = params[:width]
    height = params[:height]

    if uploaded_file.blank?
      render json: { error: 'No image uploaded' }, status: :bad_request
      return
    end

    input_path = Rails.root.join('tmp', "input_#{SecureRandom.hex(8)}#{File.extname(uploaded_file.original_filename)}")
    output_path = Rails.root.join('tmp', "output_#{SecureRandom.hex(8)}.#{format}")

    File.open(input_path, 'wb') do |file|
      file.write(uploaded_file.read)
    end

    resize_option = ""
    if width.present? && height.present?
      resize_option = "-resize #{width}x#{height}"
    elsif width.present?
      resize_option = "-resize #{width}"
    elsif height.present?
      resize_option = "-resize x#{height}"
    end

    command = "convert #{input_path} #{resize_option} #{output_path}"
    
    result = system(command)

    if result && File.exist?(output_path)
      send_file output_path, filename: "converted.#{format}", type: "image/#{format}", disposition: 'attachment'
      
      Thread.new do
        sleep 5
        File.delete(input_path) if File.exist?(input_path)
        File.delete(output_path) if File.exist?(output_path)
      end
    else
      File.delete(input_path) if File.exist?(input_path)
      render json: { error: 'Image conversion failed' }, status: :unprocessable_entity
    end
  rescue => e
    File.delete(input_path) if defined?(input_path) && File.exist?(input_path)
    File.delete(output_path) if defined?(output_path) && File.exist?(output_path)
    render json: { error: e.message }, status: :internal_server_error
  end

