  def batch_convert
    images = params[:images]
    format = params[:format]
    operations = params[:operations]

    if images.blank?
      render json: { error: 'No images uploaded' }, status: :bad_request
      return
    end

    results = []

    images.each do |uploaded_file|
      input_path = Rails.root.join('tmp', "input_#{SecureRandom.hex(8)}#{File.extname(uploaded_file.original_filename)}")
      output_path = Rails.root.join('tmp', "output_#{SecureRandom.hex(8)}.#{format}")

      File.open(input_path, 'wb') do |file|
        file.write(uploaded_file.read)
      end

      command = "convert #{input_path} #{operations} #{output_path}"
      result = `#{command} 2>&1`

      if $?.exitstatus == 0 && File.exist?(output_path)
        results << { success: true, filename: uploaded_file.original_filename }
        File.delete(output_path) if File.exist?(output_path)
      else
        results << { success: false, filename: uploaded_file.original_filename, error: result }
      end

      File.delete(input_path) if File.exist?(input_path)
    end

    render json: { results: results }
  rescue => e
    render json: { error: e.message }, status: :internal_server_error
  end
